// ---- Flow Basics ----
// Flow is a cold stream of values

// ---- Creating Flows ----
class FlowViewModel : ViewModel() {
    // ---- Simple flow ----
    private val _counter = MutableStateFlow(0)
    val counter: StateFlow<Int> = _counter.asStateFlow()

    // ---- Flow builder ----
    fun numberFlow(): Flow<Int> = flow {
        for (i in 1..5) {
            delay(500)
            emit(i)
        }
    }

    // ---- Flow with state ----
    fun countdownFlow(start: Int): Flow<Int> = flow {
        for (i in start downTo 1) {
            delay(1000)
            emit(i)
        }
    }

    // ---- Flow operators ----
    fun doubledNumbers(): Flow<Int> = flow {
        for (i in 1..10) {
            delay(200)
            emit(i)
        }
    }.map { it * 2 }

    // ---- Filter flow ----
    fun evenNumbers(): Flow<Int> = flow {
        for (i in 1..10) {
            delay(200)
            emit(i)
        }
    }.filter { it % 2 == 0 }

    // ---- Take flow ----
    fun firstThree(): Flow<Int> = flow {
        for (i in 1..10) {
            delay(200)
            emit(i)
        }
    }.take(3)

    // ---- Collect flow ----
    fun collectNumbers() {
        viewModelScope.launch {
            numberFlow().collect { value ->
                _counter.value = value
            }
        }
    }
}

// ---- Flow with UI ----
@Composable
fun FlowScreen() {
    val viewModel: FlowViewModel = viewModel()
    val counter by viewModel.counter.collectAsState()
    var flowResult by remember { mutableStateOf("") }
    var isLoading by remember { mutableStateOf(false) }

    Column(
        modifier = Modifier.fillMaxSize().padding(16.dp),
        horizontalAlignment = Alignment.CenterHorizontally,
        verticalArrangement = Arrangement.spacedBy(16.dp)
    ) {
        Text("Counter: $counter")

        Button(
            onClick = {
                isLoading = true
                flowResult = ""
                viewModel.viewModelScope.launch {
                    viewModel.numberFlow().collect { value ->
                        flowResult += "$value "
                    }
                    isLoading = false
                }
            }
        ) {
            Text("Collect Flow")
        }

        Text(flowResult)

        if (isLoading) {
            CircularProgressIndicator()
        }
    }
}

// ---- SharedFlow (hot stream) ----
class SharedFlowViewModel : ViewModel() {
    private val _events = MutableSharedFlow<String>()
    val events: SharedFlow<String> = _events.asSharedFlow()

    fun sendEvent(event: String) {
        viewModelScope.launch {
            _events.emit(event)
        }
    }
}

@Composable
fun SharedFlowScreen() {
    val viewModel: SharedFlowViewModel = viewModel()
    var events by remember { mutableStateOf(listOf<String>()) }

    LaunchedEffect(Unit) {
        viewModel.events.collect { event ->
            events = events + event
        }
    }

    Column(
        modifier = Modifier.fillMaxSize().padding(16.dp),
        horizontalAlignment = Alignment.CenterHorizontally,
        verticalArrangement = Arrangement.spacedBy(16.dp)
    ) {
        Button(
            onClick = { viewModel.sendEvent("Hello") }
        ) {
            Text("Send Hello")
        }

        Button(
            onClick = { viewModel.sendEvent("World") }
        ) {
            Text("Send World")
        }

        events.forEach { event ->
            Text(event)
        }
    }
}

